// src/common/router.ts
function logger() {
  return getLogger("router");
}
function loggerMiddleware(logger5) {
  return async (c, next) => {
    const method = c.req.method;
    const path = c.req.path;
    const startTime = Date.now();
    await next();
    const duration = Date.now() - startTime;
    logger5.debug({
      msg: "http request",
      method,
      path,
      status: c.res.status,
      dt: `${duration}ms`,
      reqSize: c.req.header("content-length"),
      resSize: c.res.headers.get("content-length"),
      userAgent: c.req.header("user-agent"),
      ...getLogHeaders() ? { allHeaders: JSON.stringify(c.req.header()) } : {}
    });
  };
}
function handleRouteNotFound(c) {
  return c.text("Not Found (RivetKit)", 404);
}
function handleRouteError(error, c) {
  const exposeInternalError = getRequestExposeInternalError(c.req.raw);
  const { statusCode, group, code, message, metadata } = deconstructError(
    error,
    logger(),
    {
      method: c.req.method,
      path: c.req.path
    },
    exposeInternalError
  );
  let encoding;
  try {
    encoding = getRequestEncoding(c.req);
  } catch (_) {
    encoding = "json";
  }
  const errorData = { group, code, message, metadata };
  const output = serializeWithEncoding(
    encoding,
    errorData,
    HTTP_RESPONSE_ERROR_VERSIONED,
    CURRENT_VERSION2,
    HttpResponseErrorSchema,
    // JSON: metadata is the raw value (will be serialized by jsonStringifyCompat)
    (value) => ({
      group: value.group,
      code: value.code,
      message: value.message,
      metadata: value.metadata
    }),
    // BARE/CBOR: metadata needs to be CBOR-encoded to ArrayBuffer
    (value) => ({
      group: value.group,
      code: value.code,
      message: value.message,
      metadata: value.metadata ? bufferToArrayBuffer(cbor3.encode(value.metadata)) : null
    })
  );
  return c.body(output, { status: statusCode });
}
function handleMetadataRequest(c, config8, runnerKind, clientEndpoint, clientNamespace, clientToken) {
  const response = {
    runtime: "rivetkit",
    version: VERSION,
    runner: {
      kind: runnerKind,
      version: config8.runner.version
    },
    actorNames: buildActorNames(config8),
    clientEndpoint,
    clientNamespace,
    clientToken
  };
  return c.json(response);
}
function handleHealthRequest(c) {
  return c.json({
    status: "ok",
    runtime: "rivetkit",
    version: VERSION
  });
}

